import React from 'react';
import { FiPackage, FiTruck, FiBox, FiGlobe, FiBriefcase, FiZap, FiTarget } from 'react-icons/fi';

// Ek service card banvnyasathi component
const ServiceCard = ({ icon, title, desc, color }) => (
  <div className="col-lg-3 col-md-4 col-sm-6 mb-4">
    <div className="card h-100 border-0 shadow-sm text-center p-4 rounded-4" 
         style={{ 
           transition: '0.3s', 
           cursor: 'pointer', 
           borderTop: `6px solid ${color}`, 
           backgroundColor: 'rgba(255, 255, 255, 0.95)' 
         }}
         onMouseOver={(e) => e.currentTarget.style.transform = 'translateY(-10px)'}
         onMouseOut={(e) => e.currentTarget.style.transform = 'translateY(0)'}
    >
      <div className="mb-3 d-flex justify-content-center" style={{ fontSize: '2.8rem', color: color }}>
        {icon}
      </div>
      <h6 className="fw-bold text-dark text-uppercase mb-2" style={{ fontSize: '0.9rem' }}>{title}</h6>
      <p className="text-muted mb-3" style={{ fontSize: '0.8rem' }}>{desc}</p>
      <button className="btn btn-outline-primary btn-sm rounded-pill px-4 mt-auto">Details</button>
    </div>
  </div>
);

const Home = () => {
  return (
    <div className="container mt-5">
      <div className="text-center py-5">
        <h1 className="fw-bold text-dark mb-2">Apni Manzil Services</h1>
        <p className="text-muted">Select a service to get started with your logistics needs</p>
      </div>

      <div className="row g-4 justify-content-center pb-5">
        {/* Tumche Sagle Services Icons Sobat */}
        <ServiceCard icon={<FiPackage />} title="Courier Services" desc="Fast & Reliable Parcel Delivery" color="#2ecc71" />
        <ServiceCard icon={<FiTruck />} title="Transport Services" desc="Heavy Loads & Trucking Solutions" color="#f1c40f" />
        <ServiceCard icon={<FiBox />} title="Packers & Movers" desc="Safe Home & Office Shifting" color="#f39c12" />
        <ServiceCard icon={<FiGlobe />} title="International" desc="Global Air & Sea Freight" color="#9b59b6" />
        <ServiceCard icon={<FiBriefcase />} title="Business MSME" desc="Bulk Logistics for Businesses" color="#3498db" />
        <ServiceCard icon={<FiTarget />} title="Tracking" desc="Real-time Order Status" color="#1abc9c" />
        <ServiceCard icon={<FiZap />} title="Express" desc="Same Day Delivery Options" color="#e74c3c" />
      </div>
    </div>
  );
};

export default Home;
